import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---------- Quote: edge & simplest cases ----------
  it.todo("empty item list -> premium 5 G (only processing fee)");

  // ---------- Single main item base premiums ----------
  it.todo("single sword (steel, ench 0, not cursed), newcomer (0 yrs, first quote) -> 100 + 10 first + 5 fee = 115 G");
  it.todo("single amulet, newcomer first quote -> 60 + 6 first + 5 = 71 G");
  it.todo("single staff, newcomer first quote -> 80 + 8 first + 5 = 93 G");
  it.todo("single potion, newcomer first quote -> 40 + 4 first + 5 = 49 G");

  // ---------- Components & blocks ----------
  it.todo("2 runes -> base 50 (no block); + 5 fee + 10% first insurance per item -> 60 G");
  it.todo("3 runes -> base 60 (block applies); newcomer first -> 60 + 6 first + 5 = 71 G");
  it.todo("4 runes -> base 100 (no block, exactly 3 required); newcomer first -> 100 + 10 + 5 = 115 G");
  it.todo("7 runes -> base 175 (no block); newcomer first -> 175 + 17.5 first = 192.5; +5 = 197.5; round up -> 198 G");
  it.todo("2 runes + 1 moonstone -> 75 G base (no block, different types)");
  it.todo("3 runes + 3 moonstones -> 120 G base (two separate blocks)");

  // ---------- Modifiers ----------
  it.todo("cursed sword (steel, ench 3), newcomer first -> 100 + 50 curse + 10 first + 5 = 165 G");
  it.todo("sword with enchantment exactly 5 -> high-ench surcharge applies; 100 + 30 + 10 first + 5 = 145 G");
  it.todo("sword with enchantment 4 -> no high-ench surcharge; 100 + 10 first + 5 = 115 G");
  it.todo("cursed sword with enchantment 5 -> both surcharges; 100 + 50 + 30 + 10 first + 5 = 195 G");

  // ---------- Loyalty & follow-up modifiers ----------
  it.todo("loyalty: customer with exactly 2 years -> 20% discount; sword: 100 - 20 + 10 first + 5 = 95 G");
  it.todo("first insurance surcharge applies even for long-standing customers (per item, not per customer)");
  it.todo("follow-up contract: 15% discount on each contract after the first (within the scenario)");

  // ---------- Multi-item policy: modifier scope ----------
  it.todo("policy with cursed sword + plain amulet -> 160 base + 50 curse + 16 first + 5 = 231 G");

  // ---------- Rounding ----------
  it.todo("rounding: premium 197.5 G -> 198 G (rounded up); payout 350.5 G -> 350 G (rounded down)");

  // ---------- Integration examples ----------
  it.todo("newcomer with cursed sword (steel, ench 3) -> 165 G");
  it.todo("long-standing 3-yr customer, second contract, cursed sword (steel, ench 7) -> 160 G");

  // ---------- Claim: standard reimbursement ----------
  it.todo("regular sword (steel, ench 3), damage 500 -> payout 400 (500 - 100 deductible)");
  it.todo("damage to a rune (no enchantment/material), damage 200 -> payout 100");

  // ---------- Claim: high-enchantment clause ----------
  it.todo("steel sword, enchantment 9, damage 1000 -> payout 400 (50% then deductible)");

  // ---------- Claim: dragon material ----------
  it.todo("dragon sword, enchantment 5, damage 800 -> payout 700 (full reimbursement minus deductible)");
  it.todo("dragon sword, enchantment 9, damage 1000 -> payout 400 (high-ench wins: 500 - 100)");
  it.todo("dragon sword, enchantment exactly 8, damage 1000 -> payout 400 (high-ench applies, then deductible)");

  // ---------- Multiple damages per claim ----------
  it.todo("dragon attack damages sword (500) and amulet (300) -> payout 600 (deductible per item)");

  // ---------- Multiple items same type ----------
  it.todo("policy with two swords -> insurance sum 2000, cap 4000");
  it.todo("policy with two swords, damages array with two sword entries -> each treated as separate damage with own deductible");
  it.todo("damages array contains more entries of a type than policy covers -> CLI exits non-zero (whole claim rejected)");

  // ---------- Cap ----------
  it.todo("policy: sword + amulet -> insurance sum 1600, cap 3200");
  it.todo("cursed sword: cap 2000 (based on unmodified insurance value; modifiers do not raise cap)");
  it.todo("policy: sword + 3 runes (block) -> insurance sum 1750 (block discount affects premium only)");
  it.todo("sword, two successive claims of 1500 each -> 1st payout 1400 (cap rem 600), 2nd payout 600 (cap rem 0)");

  // ---------- Error cases ----------
  it.todo("quote item with unknown type -> CLI exits non-zero, error on stderr, no results");
  it.todo("claim references damage for item not part of policy -> CLI exits non-zero");
  it.todo("claim with damage amount -200 -> CLI exits non-zero");

  // ---------- CLI integration ----------
  it.todo("CLI reads JSON from stdin, writes JSON results to stdout (schema example)");
});

