const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const SWORD_BASE_PREMIUM = 100;

type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const basePremiumFor = (item: Item): number => {
  if (item.type === "amulet") return 60;
  return SWORD_BASE_PREMIUM;
};

const quotePremium = (items: Item[]): number => {
  const itemsTotal = items.reduce((sum, item) => {
    const base = basePremiumFor(item);
    return sum + base + base * FIRST_INSURANCE_RATE;
  }, 0);
  return itemsTotal + PROCESSING_FEE;

